def lambda_handler(event: dict, context: Any) -> dict:
    """
    Lambda handler for API Gateway webhook events.

    Uses JSON deserialization (NOT pickle) because:
    - Webhook data comes from EXTERNAL/UNTRUSTED sources
    - pickle.loads() on untrusted data = Remote Code Execution vulnerability
    - JSON is safe, standard, and interoperable
    """
    try:
        # Parse the body from API Gateway event
        body = event.get("body", "")
        if not body:
            return {
                "statusCode": 400,
                "headers": {"Content-Type": "application/json"},
                "body": json.dumps({"error": "Empty request body"}),
            }

        # Safely deserialize JSON (NEVER use pickle for external data)
        if event.get("isBase64Encoded", False):
            import base64
            body = base64.b64decode(body).decode("utf-8")

        # Limit payload size to prevent abuse
        if len(body) > 1_000_000:  # 1MB limit
            return {
                "statusCode": 413,
                "headers": {"Content-Type": "application/json"},
                "body": json.dumps({"error": "Payload too large"}),
            }

        payload = json.loads(body)

        # Validate top-level structure
        if not isinstance(payload, dict):
            return {
                "statusCode": 400,
                "headers": {"Content-Type": "application/json"},
                "body": json.dumps({"error": "Payload must be a JSON object"}),
            }

        # Extract and process actions
        actions_data = payload.get("actions", [])
        if not isinstance(actions_data, list):
            return {
                "statusCode": 400,
                "headers": {"Content-Type": "application/json"},
                "body": json.dumps({"error": "'actions' must be an array"}),
            }

        if len(actions_data) > 100:
            return {
                "statusCode": 400,
                "headers": {"Content-Type": "application/json"},
                "body": json.dumps({"error": "Too many actions (max 100)"}),
            }

        results = []
        errors = []

        for i, action_data in enumerate(actions_data):
            try:
                action = UserAction.from_dict(action_data)
                result = process_action(action)
                results.append(result)
            except (ValueError, TypeError, KeyError) as e:
                logger.warning(f"Invalid action at index {i}: {e}")
                errors.append({"index": i, "error": str(e)})

        response_body = {
            "processed": len(results),
            "errors": len(errors),
            "results": results,
        }
        if errors:
            response_body["error_details"] = errors

        status_code = 200 if not errors else (207 if results else 400)

        return {
            "statusCode": status_code,
            "headers": {"Content-Type": "application/json"},
            "body": json.dumps(response_body),
        }

    except json.JSONDecodeError as e:
        logger.error(f"Invalid JSON in request body: {e}")
        return {
            "statusCode": 400,
            "headers": {"Content-Type": "application/json"},
            "body": json.dumps({"error": "Invalid JSON in request body"}),
        }
    except Exception as e:
        logger.error(f"Unexpected error processing webhook: {e}", exc_info=True)
        return {
            "statusCode": 500,
            "headers": {"Content-Type": "application/json"},
            "body": json.dumps({"error": "Internal server error"}),
        }